import { withSupabaseHandler } from "../../utils/withSupabaseHandler.ts";
import { getQuestions } from "../../../../../lib/questions/get_questions.js";

export default withSupabaseHandler(async (req, supabase) => {
  try {
    const { questionSetId } = await req.json();
    if (!questionSetId) return new Response(JSON.stringify({ error: "Missing questionSetId" }), { status: 400 });

    const questions = await getQuestions(supabase, questionSetId);
    return new Response(JSON.stringify(questions), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 400 });
  }
});
